import React from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';
import './Dashboard.css';

function Dashboard() {
  const projetosMock = [
    { id: 1, nome: 'Projeto Integrador 1', descricao: 'Desenvolvimento do sistema colaborativo TaskFlow.' },
    { id: 2, nome: 'Trabalho de Extensão', descricao: 'Criação de plataforma web para a comunidade externa.' },
    { id: 3, nome: 'Desenvolvimento de API Rest', descricao: 'Implementação de rotas e regras de negócio de backend.' }
  ];

  return (
    <div>
      <Navbar />
      <div className="dashboard-container">
        <h1>Meus Projetos</h1>
        <div className="projetos-grid">
          {projetosMock.map((projeto) => (
            <div key={projeto.id} className="projeto-card">
              <h3>{projeto.nome}</h3>
              <p>{projeto.descricao}</p>
              <Link to={`/projeto/${projeto.id}`} className="btn-detalhes">Ver Detalhes</Link>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
